# solution.py
"""Team Collaboration Manager.

A self-contained, thread-safe, in-memory team collaboration platform.

The module exposes a single facade -- :class:`TeamCollaborationManager` -- that
coordinates users, projects, tasks, messaging, a performance dashboard and
reporting.  It is intentionally dependency-free (standard library only) so it
can be embedded anywhere.

Design notes
------------
* **Single shared lock.** Every internal store shares one :class:`threading.RLock`
  with the manager.  All public operations are serialized through it, which keeps
  the data structures consistent under concurrent access.
* **Global identifiers.** Every entity (user, project, task, message, rating)
  draws from one monotonically increasing counter, so ids are unique across
  types and start at ``1``.
* **Copy-on-read isolation.** Getters return deep copies of stored entities so a
  caller can never mutate internal state by holding on to a returned object.
* **Injectable clock.** A ``now`` callable can be supplied for deterministic
  timestamps in tests; it defaults to :func:`datetime.datetime.now`.
"""

import copy
import csv
import enum
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from typing import Dict, List, Optional


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(enum.Enum):
    """Roles a user can hold within the platform."""

    MEMBER = "member"
    ADMIN = "admin"
    MANAGER = "manager"
    GUEST = "guest"


class TaskStatus(enum.Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(enum.Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(enum.Enum):
    """Kinds of reports the manager can produce."""

    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the platform."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not allowed to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Domain entities
# ---------------------------------------------------------------------------
@dataclass
class User:
    """A platform user."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A project owned by a user with a scheduling window."""

    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""


@dataclass
class Task:
    """A unit of work within a project."""

    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Attachment:
    """Binary attachment metadata carried by a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    """A message posted against a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """A peer rating given to a user."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Internal stores (share a single lock with the manager)
# ---------------------------------------------------------------------------
class _BaseStore:
    """A store that participates in the manager's shared locking discipline."""

    def __init__(self, lock):
        self._lock = lock


class _Store(_BaseStore):
    """A simple id-keyed entity store."""

    def __init__(self, lock):
        super().__init__(lock)
        self._items = {}  # type: Dict[int, object]

    def put(self, entity):
        self._items[entity.id] = entity

    def get(self, entity_id):
        return self._items.get(entity_id)

    def pop(self, entity_id):
        return self._items.pop(entity_id, None)

    def values(self):
        return list(self._items.values())

    def __contains__(self, entity_id):
        return entity_id in self._items

    def __len__(self):
        return len(self._items)


def _clone(entity):
    """Return a deep copy so callers cannot mutate stored state."""

    return copy.deepcopy(entity)


# ---------------------------------------------------------------------------
# Manager facade
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Thread-safe, in-memory team collaboration platform.

    Parameters
    ----------
    now:
        Optional zero-argument callable returning the current
        :class:`datetime.datetime`.  Defaults to ``datetime.now``.  Useful for
        deterministic timestamps in tests.
    """

    def __init__(self, now=None):
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now
        self._next_id = 1

        # Stores all share the manager's lock so the whole platform is guarded
        # by a single mutex.
        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Store(self._lock)  # holds Rating entities
        self.reports = _BaseStore(self._lock)  # stateless reporting component

    # -- internal helpers ---------------------------------------------------
    def _clock(self):
        return self._now()

    def _allocate_id(self):
        with self._lock:
            new_id = self._next_id
            self._next_id += 1
            return new_id

    def _require_user(self, user_id):
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id):
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message

    @staticmethod
    def _clean_text(value, label):
        if not isinstance(value, str) or not value.strip():
            raise ValidationError("{0} must be a non-empty string".format(label))
        return value.strip()

    @classmethod
    def _validate_email(cls, email):
        email = cls._clean_text(email, "email")
        if "@" not in email:
            raise ValidationError("email must contain '@'")
        return email

    @staticmethod
    def _validate_date_range(start_date, end_date):
        if end_date < start_date:
            raise ValidationError("end_date must not be before start_date")

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        """Create and store a new user."""

        with self._lock:
            username = self._clean_text(username, "username")
            email = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            for existing in self.users.values():
                if existing.username == username:
                    raise DuplicateError("username already exists")
                if existing.email == email:
                    raise DuplicateError("email already exists")
            user = User(
                id=self._allocate_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._clock(),
            )
            self.users.put(user)
            return _clone(user)

    def get_user(self, user_id):
        with self._lock:
            return _clone(self._require_user(user_id))

    def list_users(self):
        with self._lock:
            users = sorted(self.users.values(), key=lambda u: u.id)
            return [_clone(u) for u in users]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self._require_user(user_id)
            if username is not None:
                username = self._clean_text(username, "username")
                for existing in self.users.values():
                    if existing.id != user_id and existing.username == username:
                        raise DuplicateError("username already exists")
            if email is not None:
                email = self._validate_email(email)
                for existing in self.users.values():
                    if existing.id != user_id and existing.email == email:
                        raise DuplicateError("email already exists")
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None:
                user.username = username
            if email is not None:
                user.email = email
            if role is not None:
                user.role = role
            return _clone(user)

    def delete_user(self, user_id):
        with self._lock:
            self._require_user(user_id)
            for project in self.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")
            for task in self.tasks.values():
                if (
                    task.assignee_id == user_id
                    and task.status != TaskStatus.COMPLETED
                ):
                    raise ConflictError("user has an open task assigned")
            self.users.pop(user_id)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            name = self._clean_text(name, "project name")
            self._validate_date_range(start_date, end_date)
            self._require_user(owner_id)
            project = Project(
                id=self._allocate_id(),
                name=name,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description or "",
            )
            self.projects.put(project)
            return _clone(project)

    def get_project(self, project_id):
        with self._lock:
            return _clone(self._require_project(project_id))

    def list_projects(self):
        with self._lock:
            projects = sorted(self.projects.values(), key=lambda p: p.id)
            return [_clone(p) for p in projects]

    def update_project(
        self,
        project_id,
        name=None,
        start_date=None,
        end_date=None,
        description=None,
    ):
        with self._lock:
            project = self._require_project(project_id)
            new_name = project.name
            if name is not None:
                new_name = self._clean_text(name, "project name")
            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            self._validate_date_range(new_start, new_end)

            if name is not None:
                project.name = new_name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return _clone(project)

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            task_ids = [
                t.id for t in self.tasks.values() if t.project_id == project_id
            ]
            task_id_set = set(task_ids)
            for task_id in task_ids:
                self.tasks.pop(task_id)

            doomed_messages = [
                m.id
                for m in self.messages.values()
                if m.project_id == project_id or m.task_id in task_id_set
            ]
            for message_id in doomed_messages:
                self.messages.pop(message_id)

            self.projects.pop(project_id)

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = self._require_project(project_id)
            title = self._clean_text(title, "title")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not be before project start")
            task = Task(
                id=self._allocate_id(),
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._clock(),
            )
            self.tasks.put(task)
            return _clone(task)

    def get_task(self, task_id):
        with self._lock:
            return _clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tasks = [t for t in self.tasks.values() if t.project_id == project_id]
            tasks.sort(key=lambda t: t.id)
            return [_clone(t) for t in tasks]

    def list_tasks_by_assignee(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = [t for t in self.tasks.values() if t.assignee_id == user_id]
            tasks.sort(key=lambda t: t.id)
            return [_clone(t) for t in tasks]

    def assign_task(self, task_id, user_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(user_id)
            task.assignee_id = user_id
            return _clone(task)

    def reassign_task(self, task_id, user_id):
        # Reassignment shares the same semantics as assignment but reads more
        # clearly at call sites where a prior assignee is expected.
        return self.assign_task(task_id, user_id)

    def unassign_task(self, task_id):
        with self._lock:
            task = self._require_task(task_id)
            task.assignee_id = None
            return _clone(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError(
                        "deadline must not be before project start"
                    )
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            now = self._clock()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return _clone(task)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def _build_attachments(self, attachments, uploader_id):
        result = []
        if attachments:
            now = self._clock()
            for item in attachments:
                filename, data = item
                filename = self._clean_text(filename, "filename")
                result.append(
                    Attachment(
                        filename=filename,
                        size=len(data),
                        uploaded_by=uploader_id,
                        uploaded_at=now,
                    )
                )
        return result

    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        attachments=None,
        parent_id=None,
    ):
        with self._lock:
            self._require_user(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            attachment_objs = self._build_attachments(attachments, author_id)
            body = body if isinstance(body, str) else ""
            if not body.strip() and not attachment_objs:
                raise ValidationError("message must have a body or an attachment")

            message = Message(
                id=self._allocate_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=self._clock(),
                edited_at=None,
            )
            self.messages.put(message)
            return _clone(message)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            new_body = new_body if isinstance(new_body, str) else ""
            if not new_body.strip() and not message.attachments:
                raise ValidationError("message must have a body or an attachment")
            message.body = new_body
            message.edited_at = self._clock()
            return _clone(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may attach to a message"
                )
            filename = self._clean_text(filename, "filename")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=uploader_id,
                    uploaded_at=self._clock(),
                )
            )
            return _clone(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            messages = [
                m for m in self.messages.values() if m.project_id == project_id
            ]
            messages.sort(key=lambda m: m.id)
            return [_clone(m) for m in messages]

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            messages = [
                m for m in self.messages.values() if m.task_id == task_id
            ]
            messages.sort(key=lambda m: m.id)
            return [_clone(m) for m in messages]

    def delete_message(self, message_id, requester_id):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete a message")
            self.messages.pop(message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def _tasks_for_assignee(self, user_id):
        return [t for t in self.tasks.values() if t.assignee_id == user_id]

    @staticmethod
    def _completion_rate(tasks):
        if not tasks:
            return 0.0
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        return completed / len(tasks)

    @staticmethod
    def _average_completion_time(tasks):
        durations = []
        for task in tasks:
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append(
                    (task.completed_at - task.started_at).total_seconds()
                )
        if not durations:
            return None
        return sum(durations) / len(durations)

    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            return self._completion_rate(self._tasks_for_assignee(user_id))

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            return self._average_completion_time(self._tasks_for_assignee(user_id))

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if task_id is not None:
                self._require_task(task_id)
            rating = Rating(
                id=self._allocate_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._clock(),
            )
            self.performance.put(rating)
            return _clone(rating)

    def _ratings_for(self, user_id):
        ratings = [r for r in self.performance.values() if r.ratee_id == user_id]
        ratings.sort(key=lambda r: r.id)
        return ratings

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "user_id": user_id,
                "count": count,
                "average": average,
                "ratings": [_clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def _is_overdue(self, task, now):
        return (
            task.deadline is not None
            and task.status != TaskStatus.COMPLETED
            and task.deadline < now
        )

    def project_progress_report(self, project_id):
        with self._lock:
            project = self._require_project(project_id)
            tasks = [t for t in self.tasks.values() if t.project_id == project_id]
            now = self._clock()

            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1

            overdue = sum(1 for t in tasks if self._is_overdue(t, now))

            per_assignee = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id, {"total": 0, "completed": 0}
                )
                bucket["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project.id,
                "project_name": project.name,
                "total_tasks": len(tasks),
                "status_counts": status_counts,
                "completion_rate": self._completion_rate(tasks),
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def _performance_row(self, user, tasks):
        return {
            "user_id": user.id,
            "username": user.username,
            "total_tasks": len(tasks),
            "completed_tasks": sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            ),
            "completion_rate": self._completion_rate(tasks),
            "average_completion_time": self._average_completion_time(tasks),
        }

    def team_performance_report(self, project_id=None):
        with self._lock:
            scoped_project = None
            if project_id is not None:
                scoped_project = self._require_project(project_id)

            if scoped_project is not None:
                relevant_tasks = [
                    t
                    for t in self.tasks.values()
                    if t.project_id == scoped_project.id
                ]
            else:
                relevant_tasks = list(self.tasks.values())

            tasks_by_user = {}
            for task in relevant_tasks:
                if task.assignee_id is None:
                    continue
                tasks_by_user.setdefault(task.assignee_id, []).append(task)

            columns = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
            ]
            rows = []
            for user_id in sorted(tasks_by_user):
                user = self.users.get(user_id)
                if user is None:
                    continue
                rows.append(self._performance_row(user, tasks_by_user[user_id]))

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "columns": columns,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            user = self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            tasks.sort(key=lambda t: t.id)
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user.id,
                "username": user.username,
                "total_tasks": len(tasks),
                "completed_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.COMPLETED
                ),
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": [
                    {
                        "task_id": t.id,
                        "title": t.title,
                        "status": t.status.value,
                        "project_id": t.project_id,
                    }
                    for t in tasks
                ],
            }

    # ------------------------------------------------------------------
    # Report export
    # ------------------------------------------------------------------
    def export_report(self, report, report_format):
        with self._lock:
            if not isinstance(report_format, ReportFormat):
                raise ValidationError("report_format must be a ReportFormat")
            if not isinstance(report, dict):
                raise ValidationError("report must be a report dictionary")
            if report_format == ReportFormat.CSV:
                return self._export_csv(report)
            return self._export_pdf(report)

    @staticmethod
    def _stringify(value):
        if value is None:
            return ""
        if isinstance(value, (dict, list)):
            return repr(value)
        return str(value)

    def _report_to_rows(self, report):
        """Flatten a report into a list of CSV row lists (with a header)."""

        rows = report.get("rows")
        columns = report.get("columns")
        if isinstance(rows, list) and columns:
            table = [list(columns)]
            for row in rows:
                table.append([self._stringify(row.get(c)) for c in columns])
            return table
        if isinstance(rows, list) and rows and isinstance(rows[0], dict):
            keys = list(rows[0].keys())
            table = [keys]
            for row in rows:
                table.append([self._stringify(row.get(k)) for k in keys])
            return table

        # Generic key/value flattening for scalar-oriented reports.
        table = [["key", "value"]]
        for key, value in report.items():
            if key == "per_assignee" and isinstance(value, dict):
                for uid, stats in value.items():
                    table.append(
                        ["assignee_{0}".format(uid), self._stringify(stats)]
                    )
            elif key == "status_counts" and isinstance(value, dict):
                for status_name, count in value.items():
                    table.append(
                        ["status_{0}".format(status_name), self._stringify(count)]
                    )
            else:
                table.append([self._stringify(key), self._stringify(value)])
        return table

    def _export_csv(self, report):
        table = self._report_to_rows(report)
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        for row in table:
            writer.writerow(row)
        return buffer.getvalue()

    def _export_pdf(self, report):
        table = self._report_to_rows(report)
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for row in table:
            lines.append(", ".join(self._stringify(cell) for cell in row))
        return _build_pdf(lines)


# ---------------------------------------------------------------------------
# Minimal PDF generation (no third-party dependency)
# ---------------------------------------------------------------------------
def _pdf_escape(text):
    return (
        text.replace("\\", "\\\\")
        .replace("(", "\\(")
        .replace(")", "\\)")
    )


def _build_pdf(lines):
    """Build a minimal but structurally valid single-page PDF document."""

    content_parts = ["BT", "/F1 12 Tf", "1 0 0 1 72 720 Tm", "14 TL"]
    first = True
    for line in lines:
        safe = _pdf_escape(line.encode("ascii", "replace").decode("ascii"))
        if first:
            content_parts.append("({0}) Tj".format(safe))
            first = False
        else:
            content_parts.append("T* ({0}) Tj".format(safe))
    content_parts.append("ET")
    stream = "\n".join(content_parts).encode("ascii", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>"
        ),
        b"<< /Length "
        + str(len(stream)).encode("ascii")
        + b" >>\nstream\n"
        + stream
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray(b"%PDF-1.4\n")
    offsets = []
    for index, body in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += "{0} 0 obj\n".format(index).encode("ascii")
        pdf += body
        pdf += b"\nendobj\n"

    xref_offset = len(pdf)
    count = len(objects) + 1
    pdf += b"xref\n"
    pdf += "0 {0}\n".format(count).encode("ascii")
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    pdf += b"trailer\n"
    pdf += "<< /Size {0} /Root 1 0 R >>\n".format(count).encode("ascii")
    pdf += b"startxref\n"
    pdf += "{0}\n".format(xref_offset).encode("ascii")
    pdf += b"%%EOF"
    return bytes(pdf)


